import {
  useCallback,
  useEffect,
  useMemo,
  useReducer,
  useRef,
  type KeyboardEvent as ReactKeyboardEvent,
} from 'react';
import { useIntl } from 'react-intl';

import BreakpointsJS from '@dynatrace/strato-design-tokens/breakpoints-js';

import * as customTimeframeSelectorStyles from './CustomTimeframeSelector.sty.js';
import { Button } from '../../../../buttons/button/Button.js';
import { useId } from '../../../../core/hooks/useId.js';
import type { TimeErrorKey } from '../../../../core/time/shared.types.js';
import { useTimeframeSelectorStore } from '../../../../core/time/timeframeStore/useTimeframeStore.js';
import {
  getTimeBoundaryMessageData,
  validate,
} from '../../../../core/time/validation.js';
import { DateTimeRangePickerRoot } from '../../../../forms/date-time-range-picker/DateTimeRangePickerRoot.js';
import { FormFieldMessages } from '../../../../forms/forms-core/components/form-field-messages/FormFieldMessages.js';
import { Label } from '../../../../forms/forms-core/components/label/Label.js';
import { _FormFieldContext as FormFieldContext } from '../../../../forms/forms-core/contexts/FormFieldContext.js';
import { FormFieldMessageContext } from '../../../../forms/forms-core/contexts/FormFieldMessageContext.js';
import { useFormFieldContext } from '../../../../forms/forms-core/hooks/useFormFieldContext.js';
import { useFormFieldMessagesContext } from '../../../../forms/forms-core/hooks/useFormFieldMessagesContext.js';
import {
  FormFieldMessagesAction,
  formFieldMessagesReducer,
  type FormFieldMessagesReducerAction,
} from '../../../../forms/forms-core/state/formfield-messages-state-reducer.js';
import { sortTimeframeValues } from '../../../../forms/forms-core/time/helpers.js';
import {
  getFromToValues,
  parseValue,
} from '../../../../forms/forms-core/time/timeParser.js';
import type { FormFieldMessageContextState } from '../../../../forms/forms-core/types/formfield-messages.types.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { useBreakpoint } from '../../../../layouts/hooks/useBreakpoint.js';
import { InputGroup } from '../../../../layouts/input-group/InputGroup.js';
import {
  TIMEFRAMESELECTOR_ERROR_MESSAGES,
  TIMEFRAME_SELECTOR_MESSAGES,
} from '../../constants/timeframeSelectorMessages.js';
import { saveRecentTimeframe } from '../../utils/presets-helpers.js';
import { isOutsideRange } from '../../utils/timeframe-selection.js';

/**
 * Custom Timeframe Selector component used inside the overlay.
 */
export const CustomTimeframeSelector = () => {
  const ref = useTimeframeSelectorStore(
    (state) => state.dateTimeRangePickerRef,
  );
  const intl = useIntl();
  const value = useTimeframeSelectorStore(
    (state) => state.dateTimeRangePickerTimeframe,
  );
  const onChange = useTimeframeSelectorStore(
    (state) => state.setTimeframeSelectorTimeframe,
  );
  const min = useTimeframeSelectorStore((state) => state.min);
  const max = useTimeframeSelectorStore((state) => state.max);
  const precision = useTimeframeSelectorStore((state) => state.precision);
  const required = useTimeframeSelectorStore((state) => state.required);
  const dateTimeRangePickerError = useTimeframeSelectorStore(
    (state) => state.dateTimeRangePickerError,
  );
  const formatString = useTimeframeSelectorStore((state) => state.formatString);

  const {
    state: { showError },
  } = useFormFieldMessagesContext();
  const rootRef = useRef<HTMLDivElement | null>(null);

  const dateTimeRangePickerId = useId();

  const hintId = useId();

  const labelId = useId();

  const { from, to } = parseValue(value);

  const { required: contextRequired } = useFormFieldContext();

  const callback = useCallback(
    (
      state: FormFieldMessageContextState,
      action: FormFieldMessagesReducerAction,
    ) => formFieldMessagesReducer(state, action),
    [],
  );

  const [state, dispatch] = useReducer(callback, {
    customMessages: [],
    formControlMessages: [],
    showError: showError,
    isTouched: showError,
  });
  const applyButtonDataDtName = 'Apply';
  const { valueFrom, valueTo } = getFromToValues(value);
  const applyButtonDataDtProperties = `valueFrom:${valueFrom},valueTo:${valueTo}`;

  // Track the previous validation error so validate() can clean up stale
  // messages in the local FormFieldMessageContext.
  const previousErrorRef = useRef<TimeErrorKey | undefined>();

  // Track validation errors on every value change.
  // If the outer TimeframeSelector already shows an error, propagate that
  // visibility to the DateTimeRangePicker context immediately.
  useEffect(() => {
    previousErrorRef.current = validate(value, min, max, {
      formMessageDispatch: dispatch,
      formerError: previousErrorRef.current,
      precision,
      showError,
      checkOrder: true,
      ref,
      expectedFormat: formatString,
      valueMode: 'dateTimePicker',
      required: required || contextRequired,
      errorMessages: TIMEFRAMESELECTOR_ERROR_MESSAGES,
    });

    if (!required && !contextRequired) {
      if (!from && to?.value === 'now()') {
        dispatch({
          type: FormFieldMessagesAction.ADDMESSAGE,
          payload: {
            id: hintId,
            variant: 'error',
            message: intl.formatMessage(
              TIMEFRAMESELECTOR_ERROR_MESSAGES.missingFrom,
            ),
            messageType: 'formcontrol',
            validityStateKey: 'customError',
          },
        });
        return;
      }

      if (!to && from?.value === 'now()') {
        dispatch({
          type: FormFieldMessagesAction.ADDMESSAGE,
          payload: {
            id: hintId,
            variant: 'error',
            message: intl.formatMessage(
              TIMEFRAMESELECTOR_ERROR_MESSAGES.missingTo,
            ),
            messageType: 'formcontrol',
            validityStateKey: 'customError',
          },
        });
        return;
      }
    }
  }, [
    value,
    min,
    max,
    dispatch,
    precision,
    formatString,
    required,
    contextRequired,
    showError,
    ref,
  ]);

  /** Handle form submission. */
  const handleApply = useCallback(() => {
    dispatch({
      type: FormFieldMessagesAction.SETISTOUCHED,
      payload: { isTouched: true },
    });

    if (dateTimeRangePickerError) {
      return;
    }

    const currentValue = ref.current?.getCurrentValue();
    const refFrom = currentValue?.from?.value;
    const refTo = currentValue?.to?.value;

    let currentTimeframe = value;

    const onlyFromIsEmpty = !refFrom && !!refTo && refTo !== 'now()';
    const onlyToIsEmpty = !refTo && !!refFrom && refFrom !== 'now()';

    if (onlyFromIsEmpty || onlyToIsEmpty) {
      // If one of the fields is empty, fill it with 'Now'
      const from = ref.current?.inputRef.from?.value || 'now()';
      const to = ref.current?.inputRef.to?.value || 'now()';
      const parsedTimeframe = parseValue({ from, to }, false, precision);

      if (parsedTimeframe.from && parsedTimeframe.to) {
        // Exit if the parsed timeframe is out of bounds
        if (
          isOutsideRange(
            {
              from: parsedTimeframe.from.value,
              to: parsedTimeframe.to.value,
            },
            min?.value,
            max?.value,
          )
        ) {
          return;
        }

        const sortedTimeframe = sortTimeframeValues({
          from: parsedTimeframe.from,
          to: parsedTimeframe.to,
        });

        if (sortedTimeframe.from && sortedTimeframe.to) {
          currentTimeframe = {
            from: sortedTimeframe.from,
            to: sortedTimeframe.to,
          };
        }
      }
    }

    /** parse date-picker inputs to have latest expression values on form submission */
    const { from, to } = currentTimeframe
      ? parseValue(currentTimeframe, false, precision)
      : { from: null, to: null };

    if (from && to) {
      const timeframe = { from, to };
      onChange(timeframe);
      saveRecentTimeframe(timeframe);
      return;
    }

    if (!required && !contextRequired) {
      const hasFromValue = Boolean(refFrom);
      const hasToValue = Boolean(refTo);

      // For optional selector, only emit null when both sides are truly empty.
      // Partial values must remain unapplied.
      if (!hasFromValue && !hasToValue) {
        onChange(null);
      }
    }
  }, [
    dateTimeRangePickerError,
    ref,
    value,
    precision,
    required,
    contextRequired,
    min,
    max,
    onChange,
  ]);

  const handleKeyDown = useCallback(
    (e: ReactKeyboardEvent<HTMLDivElement>) => {
      if (
        e.key !== 'Enter' ||
        // Checks if the event target is a child of the DateTimeRangePicker root element ref.
        !ref.current?.element?.contains(e.target as HTMLElement)
      ) {
        return;
      }

      ref.current?.validate();
      handleApply();
    },
    [handleApply, ref],
  );

  const isScreenLargerThanMobile = useBreakpoint(
    `(min-width: ${BreakpointsJS.Max.Mobile}px)`,
    true,
  );

  useEffect(() => {
    const timeBoundaryMessageData = getTimeBoundaryMessageData(
      {
        from,
        to,
      },
      min,
      max,
      precision,
      false,
    );

    if (!timeBoundaryMessageData) {
      if (!required && !contextRequired) {
        if (!from && to?.value === 'now()') {
          dispatch({
            type: FormFieldMessagesAction.ADDMESSAGE,
            payload: {
              id: hintId,
              variant: 'error',
              message: intl.formatMessage(
                TIMEFRAMESELECTOR_ERROR_MESSAGES.missingFrom,
              ),
              messageType: 'formcontrol',
              validityStateKey: 'customError',
            },
          });
          return;
        }

        if (!to && from?.value === 'now()') {
          dispatch({
            type: FormFieldMessagesAction.ADDMESSAGE,
            payload: {
              id: hintId,
              variant: 'error',
              message: intl.formatMessage(
                TIMEFRAMESELECTOR_ERROR_MESSAGES.missingTo,
              ),
              messageType: 'formcontrol',
              validityStateKey: 'customError',
            },
          });
          return;
        }
      }

      dispatch({
        type: FormFieldMessagesAction.REMOVEMESSAGE,
        payload: {
          id: hintId,
          messageType: 'formcontrol',
        },
      });
      return;
    }

    dispatch({
      type: FormFieldMessagesAction.ADDMESSAGE,
      payload: {
        id: hintId,
        variant: 'hint',
        message: intl.formatMessage(
          TIMEFRAMESELECTOR_ERROR_MESSAGES[timeBoundaryMessageData.errorKey],
          timeBoundaryMessageData.values,
        ),
        messageType: 'formcontrol',
        validityStateKey: 'customError',
      },
    });
  }, [
    min,
    max,
    dispatch,
    intl,
    precision,
    hintId,
    from,
    to,
    required,
    contextRequired,
  ]);

  const messageContextValue = useMemo(
    () => ({
      dispatch,
      state,
    }),
    [dispatch, state],
  );

  return (
    <div ref={rootRef} className={customTimeframeSelectorStyles.overlayRoot}>
      <FormFieldMessageContext.Provider value={messageContextValue}>
        <Flex className={customTimeframeSelectorStyles.wrapper}>
          <div onKeyDown={handleKeyDown}>
            <FormFieldContext.Provider value={{}}>
              <fieldset
                className={customTimeframeSelectorStyles.fieldset}
                aria-labelledby={labelId}
              >
                <Label
                  htmlFor={dateTimeRangePickerId}
                  required={required || contextRequired}
                  id={labelId}
                >
                  {intl.formatMessage(
                    TIMEFRAME_SELECTOR_MESSAGES.timeframeLabel,
                  )}
                </Label>
                <InputGroup style={{ gridAutoColumns: '1fr auto' }}>
                  <DateTimeRangePickerRoot
                    ref={ref}
                    id={dateTimeRangePickerId}
                    required={required || contextRequired}
                    style={{ gridTemplateColumns: '1fr auto' }}
                    onBlur={(event) => {
                      const hasPresetItemSelected =
                        event.relatedTarget?.getAttribute('role') === 'option';
                      const isActiveElementInside =
                        ref.current?.element?.contains(document.activeElement);

                      if (hasPresetItemSelected || isActiveElementInside) {
                        return;
                      }

                      dispatch({
                        type: FormFieldMessagesAction.SETISTOUCHED,
                        payload: { isTouched: true },
                      });
                    }}
                  />
                  {isScreenLargerThanMobile && (
                    <Button
                      color="primary"
                      variant="accent"
                      type="submit"
                      onClick={handleApply}
                      style={{
                        alignSelf: 'end',
                        borderTopLeftRadius: 0,
                        borderBottomLeftRadius: 0,
                      }}
                      data-dt-name={applyButtonDataDtName}
                      data-dt-properties={applyButtonDataDtProperties}
                    >
                      {intl.formatMessage(
                        TIMEFRAME_SELECTOR_MESSAGES.applyButton,
                      )}
                    </Button>
                  )}
                </InputGroup>
              </fieldset>
            </FormFieldContext.Provider>
          </div>
          <FormFieldMessages />
        </Flex>
        {!isScreenLargerThanMobile && (
          <Button
            color="primary"
            variant="accent"
            type="submit"
            style={{ alignSelf: 'end' }}
            onClick={handleApply}
            data-dt-name={applyButtonDataDtName}
            data-dt-properties={applyButtonDataDtProperties}
          >
            {intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.applyButton)}
          </Button>
        )}
      </FormFieldMessageContext.Provider>
    </div>
  );
};

CustomTimeframeSelector['displayName'] = 'CustomTimeframeSelector';
